};

type PlannedChange = {
	kind: string;
	target: string;
	action: string;
	reason: string;
	requiresUserConfirmation: boolean;
	wouldWrite: boolean;
};

type AppliedChange = {
	key: string;
	target: string;
	action: string;
	wrote: boolean;
};

type Report = {
	ok: boolean;
	mode: "dry-run" | "apply";
	phase: "configure-local";
	facts: Facts;
	checks: Check[];
	plannedChanges: PlannedChange[];
	appliedChanges?: AppliedChange[];
