};

const GENERATED_SECRET_KEYS = [
	"ROOT_PASSWORD",
	"AUTH_SECRET",
	"CRON_SECRET",
	"MEDIATOR_SECRET",
] as const;

const EXTERNAL_INPUT_KEYS = [
	"TURSO_DATABASE_URL",
