	}

	if (redactedCredentialUrl.startsWith("git@github.com:")) {
		return "git@github.com:<redacted>/<redacted>.git";
	}

	return redactedCredentialUrl;
}

function parseEnvFile(filePath: string) {
	if (!existsSync(filePath)) {
